const commonRules = (name: string, th = true) => th ? [`ใช้โลโก้ ${name} อย่างชัดเจนและอ่านง่าย`, "ห้ามบิดเบือน ยืด เปลี่ยนสี หรือออกแบบใหม่", "วางโลโก้ให้สะอาด ไม่รกรุงรัง"] : [`Use the official ${name} logo clearly and readably.`, "Do not distort, stretch, recolor, or redesign the logo.", "Keep placement clean and uncluttered."];
