const riskyEn = ["cures", "instant result", "treats disease", "guaranteed result"];
function text(category: string, shortPos: string, positioning: string, audience: string, voice: string, visualStyle: string, name: string, lang: Lang): TextSet {
  const th = lang === "th";
  return { category, shortPos, positioning, audience, voice, visualStyle, logoRules: commonRules(name, th), doList: th ? ["ใช้ภาษาชัดเจนและเข้าใจง่าย", "เน้นประโยชน์ในชีวิตประจำวัน", "รักษา claim ให้ปลอดภัยและรับผิดชอบ"] : ["Use clear and easy-to-understand language.", "Highlight daily-life benefits.", "Keep claims responsible and safe."], dontList: th ? ["ห้ามอ้างผลรักษาโรค", "ห้ามใช้คำเกินจริงหรือรับประกันผล", "หลีกเลี่ยงโทนขายแรงเกินไป"] : ["Do not claim disease treatment.", "Do not overpromise or guarantee results.", "Avoid aggressive hard-selling tone."], safeWords: th ? safeTh : safeEn, riskyWords: th ? riskyTh : riskyEn, safeExamples: th ? ["ช่วยดูแลอย่างเหมาะสมเมื่อใช้ต่อเนื่อง", "ออกแบบเพื่อการใช้งานในชีวิตประจำวัน"] : ["Helps support daily care with consistent use.", "Designed for practical everyday routines."], riskyExamples: th ? ["❌ หายขาด 100% → ใช้: ช่วยดูแล", "❌ เห็นผลทันที → ใช้: ใช้ต่อเนื่อง"] : ["❌ Cures 100% → Use: helps care", "❌ Instant result → Use: with consistent use"], promptCore: th ? `${name} ควรพูดด้วยโทน ${voice} ภาพควรเป็น ${visualStyle} และหลีกเลี่ยง claim เกินจริง` : `${name} should speak with this voice: ${voice}. Visuals should feel like ${visualStyle}. Avoid exaggerated claims.` };
}
